import{_ as e,o as r,c as d,aj as o}from"./chunks/framework.DpVzuYkC.js";const E=JSON.parse('{"title":"Tuwunel","description":"","frontmatter":{},"headers":[],"relativePath":"tuwunel/index.md","filePath":"tuwunel/README.md"}'),a={name:"tuwunel/index.md"};function n(l,t,u,_,i,c){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="tuwunel" tabindex="-1">Tuwunel <a class="header-anchor" href="#tuwunel" aria-label="Permalink to “Tuwunel”">​</a></h1><p><a href="https://tuwunel.chat/" target="_blank" rel="noreferrer">Office Web</a> - <a href="https://github.com/matrix-construct/tuwunel" target="_blank" rel="noreferrer">Source</a> - <a href="https://hub.docker.com/r/jevolk/tuwunel" target="_blank" rel="noreferrer">Docker Image</a> - <a href="https://matrix-construct.github.io/tuwunel/deploying/docker.html" target="_blank" rel="noreferrer">Document</a></p><hr><blockquote><p><a href="https://tuwunel.chat/" target="_blank" rel="noreferrer">Tuwunel</a> 是一个功能强大的 Matrix 自建服务器。</p></blockquote><hr><ul><li><a href="https://github.com/matrix-construct/tuwunel/blob/main/docs/deploying/docker-compose.yml" target="_blank" rel="noreferrer">docker-compose.yml</a></li></ul><table tabindex="0"><thead><tr><th>环境变量</th><th>默认值</th><th>描述</th></tr></thead><tbody><tr><td>TUWUNEL_SERVER_NAME</td><td>(必须手动设置，无默认)</td><td>服务器名称（域名），例如 <code>matrix.example.com</code>。<strong>必须修改</strong>，设置后不可更改（除非重置数据库）。用于用户ID、房间ID后缀。</td></tr><tr><td>TUWUNEL_DATABASE_PATH</td><td>/var/lib/tuwunel</td><td>数据存储目录（包含数据库、媒体文件等）。建议映射为持久化卷。</td></tr><tr><td>TUWUNEL_PORT</td><td>8008</td><td>tuwunel 监听的 HTTP 端口（客户端API和联邦端口）。Docker 中常映射为 8008 或其他端口如 6167。</td></tr><tr><td>TUWUNEL_ADDRESS</td><td>[&quot;127.0.0.1&quot;, &quot;::1&quot;]</td><td>监听的 IP 地址。公网/Docker 部署通常改为 <code>0.0.0.0</code> 以允许外部访问。</td></tr><tr><td>TUWUNEL_MAX_REQUEST_SIZE</td><td>25165824 (≈24 MiB)</td><td>最大文件上传大小（字节）。示例中设置为 20000000（≈20 MB）。</td></tr><tr><td>TUWUNEL_ALLOW_REGISTRATION</td><td>false</td><td>是否允许新用户注册。建议开启时必须配合注册令牌使用。</td></tr><tr><td>TUWUNEL_REGISTRATION_TOKEN</td><td>(无默认，必须设置)</td><td>注册时用户必须输入的令牌（字符串）。开启注册时强烈推荐设置。</td></tr><tr><td>TUWUNEL_YES_I_AM_VERY_VERY_SURE_I_WANT_AN_OPEN_REGISTRATION_SERVER_PRONE_TO_ABUSE</td><td>false</td><td><strong>极度危险</strong>：设为 true 允许完全开放、无令牌注册，极易被机器人/垃圾账号滥用，仅在明确了解风险时使用。</td></tr><tr><td>TUWUNEL_ALLOW_FEDERATION</td><td>true</td><td>是否允许联邦（与其他 Matrix 服务器互通）。关闭后成为纯私有服务器。</td></tr><tr><td>TUWUNEL_TRUSTED_SERVERS</td><td>[&quot;matrix.org&quot;]</td><td>信任的密钥服务器列表，用于验证其他服务器的签名。通常保留 matrix.org。</td></tr><tr><td>TUWUNEL_WELL_KNOWN__SERVER</td><td>your.domain.name:443</td><td>根域委托配置，指定服务器地址（用于客户端发现）。</td></tr><tr><td>TUWUNEL_WELL_KNOWN__CLIENT</td><td><a href="https://your.domain.name" target="_blank" rel="noreferrer">https://your.domain.name</a></td><td>根域委托配置，指定客户端 URL。</td></tr><tr><td>TUWUNEL_LOG</td><td>info</td><td>日志级别（可选项：trace / debug / info / warn / error）。可附加过滤器，如 <code>warn,state_res=warn</code>。</td></tr></tbody></table><ul><li><a href="https://matrix-construct.github.io/tuwunel/deploying/root-domain-delegation.html?highlight=TUWUNEL_WELL_KNOWN__#configuration" target="_blank" rel="noreferrer">配置文件 <code>/etc/tuwunel/tuwunel.toml</code></a></li></ul><blockquote><p>示例：<a href="https://matrix-construct.github.io/tuwunel/configuration/examples.html" target="_blank" rel="noreferrer">https://matrix-construct.github.io/tuwunel/configuration/examples.html</a></p></blockquote>',9)])])}const s=e(a,[["render",n]]);export{E as __pageData,s as default};
